import{c as t,Q as r,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Skill Issue: Harness Engineering for Coding Agents","description":"","frontmatter":{"url":"https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents","title":"Skill Issue: Harness Engineering for Coding Agents","date":"2026-03-12T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-12-skill-issue-harness-engineering.md","filePath":"research/ai-articles/scored/2026-03-12-skill-issue-harness-engineering.md","lastUpdated":1779796674000}'),a={name:"research/ai-articles/scored/2026-03-12-skill-issue-harness-engineering.md"};function i(o,e,l,d,g,h){return r(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="skill-issue-harness-engineering-for-coding-agents" tabindex="-1">Skill Issue: Harness Engineering for Coding Agents <a class="header-anchor" href="#skill-issue-harness-engineering-for-coding-agents" aria-label="Permalink to &quot;Skill Issue: Harness Engineering for Coding Agents&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents" target="_blank" rel="noreferrer">https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents</a><br><strong>作者</strong>：Kyle（HumanLayer）<br><strong>發表日期</strong>：2026-03-12<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>Coding Agent 的失敗主要是<strong>配置問題，而非模型限制</strong>。作者引入「harness engineering」——透過配置點（system prompts、tools、skills、sub-agents）來優化 Agent 的執行環境，而不是等待更好的模型。</p><blockquote><p>「在把 Agent 失敗歸因於模型限制之前，先檢查 harness。」</p></blockquote><h3 id="harness-engineering-與-context-engineering-的關係" tabindex="-1">Harness Engineering 與 Context Engineering 的關係 <a class="header-anchor" href="#harness-engineering-與-context-engineering-的關係" aria-label="Permalink to &quot;Harness Engineering 與 Context Engineering 的關係&quot;">​</a></h3><p>Harness engineering 是 <strong>context engineering 的子集</strong>，核心問題是：</p><ol><li>Agent 如何獲得新能力？</li><li>不在訓練資料中的代碼庫知識如何教導 Agent？</li><li>如何在提示詞指令之外增加確定性？</li><li>如何防止 context window 快速膨脹？</li></ol><h3 id="五大配置點-configuration-surfaces" tabindex="-1">五大配置點（Configuration Surfaces） <a class="header-anchor" href="#五大配置點-configuration-surfaces" aria-label="Permalink to &quot;五大配置點（Configuration Surfaces）&quot;">​</a></h3><h4 id="_1-claude-md-agents-md-文件" tabindex="-1">1. CLAUDE.md / AGENTS.md 文件 <a class="header-anchor" href="#_1-claude-md-agents-md-文件" aria-label="Permalink to &quot;1. CLAUDE.md / AGENTS.md 文件&quot;">​</a></h4><ul><li>ETH Zurich 研究：LLM 生成的文件<strong>損害</strong>效能；精心撰寫的人工文件帶來適度提升（~4%）</li><li>最佳實踐：保持 <strong>60 行以下</strong>，使用<strong>漸進式揭露（progressive disclosure）</strong></li></ul><h4 id="_2-mcp-servers-工具擴展" tabindex="-1">2. MCP Servers（工具擴展） <a class="header-anchor" href="#_2-mcp-servers-工具擴展" aria-label="Permalink to &quot;2. MCP Servers（工具擴展）&quot;">​</a></h4><ul><li>工具描述消耗系統提示 token</li><li>過多工具<strong>降低</strong>效能</li><li>對有良好文件的工具，直接 CLI 使用往往優於 MCP Server</li><li><strong>原則</strong>：只啟用需要的 Server</li></ul><h4 id="_3-skills-可重用知識模組" tabindex="-1">3. Skills（可重用知識模組） <a class="header-anchor" href="#_3-skills-可重用知識模組" aria-label="Permalink to &quot;3. Skills（可重用知識模組）&quot;">​</a></h4><p>漸進式揭露的核心機制——Agent 只在需要時取用能力：</p><ul><li>打包指令、markdown 文件、CLI/執行檔參考</li><li>採用前需安全審查</li></ul><h4 id="_4-sub-agents-隔離-context" tabindex="-1">4. Sub-Agents（隔離 Context） <a class="header-anchor" href="#_4-sub-agents-隔離-context" aria-label="Permalink to &quot;4. Sub-Agents（隔離 Context）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>優勢</th><th>說明</th></tr></thead><tbody><tr><td><strong>Context 防火牆</strong></td><td>防止中間噪音在父執行緒累積</td></tr><tr><td><strong>一致性</strong></td><td>長期多 session 項目保持聚焦</td></tr><tr><td><strong>成本優化</strong></td><td>按任務選擇模型（Haiku 研究、Sonnet 實作）</td></tr><tr><td><strong>避免 Context Rot</strong></td><td>Chroma 研究記錄的問題</td></tr></tbody></table><p>最適用場景：代碼庫探索、模式分析、資訊研究。</p><h4 id="_5-hooks-事件驅動腳本" tabindex="-1">5. Hooks（事件驅動腳本） <a class="header-anchor" href="#_5-hooks-事件驅動腳本" aria-label="Permalink to &quot;5. Hooks（事件驅動腳本）&quot;">​</a></h4><ul><li>執行驗證檢查（typecheck、formatting）</li><li>管理核准與拒絕</li><li>建立通知與整合</li><li>在 session 中途浮現 build/type 錯誤</li></ul><h3 id="反向壓力機制-back-pressure" tabindex="-1">反向壓力機制（Back-Pressure） <a class="header-anchor" href="#反向壓力機制-back-pressure" aria-label="Permalink to &quot;反向壓力機制（Back-Pressure）&quot;">​</a></h3><p>驗證系統讓 Agent 能驗證自己的工作：</p><ul><li>Type checking 和 builds</li><li>單元測試和整合測試</li><li>程式碼覆蓋率回報</li><li>UI 互動測試</li></ul><p><strong>關鍵原則</strong>：只浮現<strong>錯誤</strong>，保持成功輸出靜默 — 保護 context window 效率。</p><h3 id="什麼有效-vs-什麼無效" tabindex="-1">什麼有效 vs. 什麼無效 <a class="header-anchor" href="#什麼有效-vs-什麼無效" aria-label="Permalink to &quot;什麼有效 vs. 什麼無效&quot;">​</a></h3><table tabindex="0"><thead><tr><th>有效</th><th>無效</th></tr></thead><tbody><tr><td>從簡單開始；只在遇到真實失敗後才加配置</td><td>在看到真實失敗之前預先設計理想配置</td></tr><tr><td>把經過測試的配置發佈給整個團隊</td><td>「以防萬一」安裝 skill/server</td></tr><tr><td>優化迭代速度而非第一次嘗試的成功率</td><td>每次 session 後跑完整測試套件</td></tr><tr><td>謹慎修剪暴露的能力至實際需求</td><td>過度設計工具存取權限</td></tr></tbody></table><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>Back-pressure = cc-workspace 的 pre-commit hooks</strong>：只在錯誤時輸出、成功靜默，這正是現有 hook 設計應遵循的原則</li><li><strong>Skills 的漸進式揭露</strong>：RESOLVER.md + @-import 機制的理論基礎</li><li><strong>Sub-agent 按任務模型選擇</strong>：haiku-implementer（研究）→ implementer（跨模組）的分層已在實踐</li><li><strong>60 行以下的 CLAUDE.md</strong>：與 OpenAI Codex 文章和 Addy Osmani 的建議完全一致</li><li><strong>MCP 謹慎原則</strong>：只啟用需要的 MCP server，避免工具列表膨脹 context</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接講 Claude Code 的五大配置點，與 cc-workspace 現有設計一一對應，可立即對照審計</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Back-pressure 機制和「失敗前不加配置」的哲學有新意；但大部分是對已知概念的整合</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>引用 ETH Zurich 和 Chroma 研究，但本文是 blog，無獨立實驗數據</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>五大配置點有具體說明，但每個都是概述，缺乏實作細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>通用 coding agent harness 優化模式，不限 Claude Code</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.55/10</strong></td><td>9×0.3 + 7×0.2 + 6×0.2 + 7×0.15 + 8×0.15 = 2.7+1.4+1.2+1.05+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（配置點框架與 back-pressure 原則）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>將 back-pressure「只浮現錯誤、成功靜默」原則寫入 pre-commit hook 設計規範</li><li>確認 MCP server 清單，移除不必要的已啟用 server</li></ul>',37)])])}const b=t(a,[["render",i]]);export{u as __pageData,b as default};
